diff --git a/llvm/lib/Transforms/Utils/LoopUnroll.cpp b/llvm/lib/Transforms/Utils/LoopUnroll.cpp
index ad5670ae3317..f6137f26988f 100644
--- a/llvm/lib/Transforms/Utils/LoopUnroll.cpp
+++ b/llvm/lib/Transforms/Utils/LoopUnroll.cpp
@@ -438,6 +438,40 @@ static bool canHaveUnrollRemainder(const Loop *L) {

 /// Unroll the given loop by Count. The loop must be in LCSSA form.  Unrolling
 /// can only fail when the loop's latch block is not terminated by a conditional
+
+// Helper function to fix exit phi nodes after loop simplification
+static void fixExitPhisAfterSimplification(Loop *L, LoopInfo *LI) {
+  if (!L) return;
+  
+  SmallVector<BasicBlock *, 8> ExitBlocks;
+  L->getUniqueExitBlocks(ExitBlocks);
+  
+  for (BasicBlock *ExitBB : ExitBlocks) {
+    for (PHINode &PN : ExitBB->phis()) {
+      // Check each incoming value
+      for (unsigned i = 0, e = PN.getNumIncomingValues(); i < e; ++i) {
+        Value *V = PN.getIncomingValue(i);
+        BasicBlock *IncomingBB = PN.getIncomingBlock(i);
+        
+        // If the value is a phi node in the incoming block that has been
+        // simplified (e.g., has only one incoming value), use that value
+        if (PHINode *IncomingPHI = dyn_cast<PHINode>(V)) {
+          if (IncomingPHI->getParent() == IncomingBB) {
+            // If the phi node has been simplified to have only one incoming
+            // value, use that value
+            if (IncomingPHI->getNumIncomingValues() == 1) {
+              PN.setIncomingValue(i, IncomingPHI->getIncomingValue(0));
+              // If the phi node is now dead, mark it for deletion
+              if (IncomingPHI->use_empty()) {
+                IncomingPHI->eraseFromParent();
+              }
+            }
+          }
+        }
+      }
+    }
+  }
+}
 /// branch instruction. However, if the trip count (and multiple) are not known,
 /// loop unrolling will mostly produce more code that is no faster.
 ///
@@ -1012,6 +1046,8 @@ llvm::UnrollLoop(Loop *L, UnrollLoopOptions ULO, LoopInfo *LI,
   // doing constant propagation and dead code elimination as we go.
   simplifyLoopAfterUnroll(L, !CompletelyUnroll && ULO.Count > 1, LI, SE, DT, AC,
                           TTI, AA);
+  // Fix exit phi nodes that might have incorrect values after simplification
+  fixExitPhisAfterSimplification(L, LI);

   NumCompletelyUnrolled += CompletelyUnroll;
   ++NumUnrolled;
diff --git a/llvm/lib/Transforms/Utils/BasicBlockUtils.cpp b/llvm/lib/Transforms/Utils/BasicBlockUtils.cpp
index 7bffd4da75a5..276e666f6db5 100644
--- a/llvm/lib/Transforms/Utils/BasicBlockUtils.cpp
+++ b/llvm/lib/Transforms/Utils/BasicBlockUtils.cpp
@@ -1314,6 +1314,29 @@ static void UpdatePHINodes(BasicBlock *OrigBB, BasicBlock *NewBB,
       if (PredSet.count(IncomingBB)) {
         Value *V = PN->removeIncomingValue(i, false);
         NewPHI->addIncoming(V, IncomingBB);
+          // Fix for PR114879: If the value V is from a peeled iteration
+          // (has ".peel" in its name) but the incoming block is not from
+          // a peeled iteration, we might need to use a different value.
+          // This can happen when a loop is peeled and then simplified,
+          // and exit phi nodes get incorrect values.
+          if (Instruction *I = dyn_cast<Instruction>(V)) {
+            if (I->getName().contains(".peel") && 
+                !IncomingBB->getName().contains(".peel")) {
+              // Try to find a better value. If the instruction is a phi node
+              // that has been simplified (e.g., has constant incoming values),
+              // use the simplified value.
+              if (PHINode *PHI = dyn_cast<PHINode>(I)) {
+                // Check if all incoming values are the same
+                Value *FirstVal = nullptr;
+                bool AllSame = true;
+                for (unsigned j = 0, e = PHI->getNumIncomingValues(); j < e; ++j) {
+                  if (j == 0) FirstVal = PHI->getIncomingValue(j);
+                  else if (PHI->getIncomingValue(j) != FirstVal) AllSame = false;
+                }
+                if (AllSame && FirstVal) V = FirstVal;
+              }
+            }
+          }
       }
     }

